import java.util.Optional;
public class FilterDemo {
    public static void main(String[] args) {
        Optional<Integer> opt = Optional.of(42);
        System.out.println(opt.filter(n -> n > 10).isPresent());
        System.out.println(opt.filter(n -> n > 100).isPresent());
        Optional.of("hi").ifPresent(s -> System.out.println(s.toUpperCase()));
    }
}
